import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { TranslateService } from '@ngx-translate/core';
import { InvestmentsService, InvestmentItem } from '../../services/investments.service';
import { CategoryService, Category } from '../../services/category.service';
import { TableGroupingService, GroupedData } from '../../shared/table-grouping.service';

@Component({
  selector: 'app-investments',
  templateUrl: './investments.component.html',
  styleUrls: ['./investments.component.css']
})
export class InvestmentsComponent implements OnInit {
  investmentItems: InvestmentItem[] = [];
  filteredItems: InvestmentItem[] = [];
  groupedData: GroupedData<InvestmentItem>[] = [];
  groupByField: string = 'none';
  showForm = false;
  editingItem: InvestmentItem | null = null;
  searchTerm = '';
  loading = false;
  error: string | null = null;

  // Categories
  investmentTypes: Category[] = [];

  // Date filtering
  selectedYear: number = new Date().getFullYear();
  selectedMonth: number = new Date().getMonth();
  viewMode: 'all' | 'yearly' | 'monthly' | 'daily' = 'all';
  availableYears: number[] = [];
  availableMonths: string[] = [];

  investmentForm: FormGroup;

  constructor(
    private investmentsService: InvestmentsService,
    private categoryService: CategoryService,
    private fb: FormBuilder,
    private translate: TranslateService
  ) {
    this.investmentForm = this.fb.group({
      date: ['', Validators.required],
      type: ['', Validators.required],
      amount: ['', [Validators.required, Validators.min(0)]],
      description: ['']
    });
  }

  ngOnInit(): void {
    this.generateAvailableYears();
    this.loadMonths();
    this.loadCategories();
    this.loadInvestments();
    
    this.translate.onLangChange.subscribe(() => {
      this.loadMonths();
    });
  }

  loadCategories(): void {
    this.categoryService.getCategoriesByType('investment').subscribe({
      next: (data) => {
        this.investmentTypes = data;
      },
      error: (error) => {
        console.error('Error loading investment types:', error);
      }
    });
  }

  getCategoryName(category: Category): string {
    const currentLang = this.translate.currentLang;
    return currentLang === 'ar' ? category.name_ar : category.name_en;
  }

  loadMonths(): void {
    this.availableMonths = [
      this.translate.instant('MONTHS.JANUARY'),
      this.translate.instant('MONTHS.FEBRUARY'),
      this.translate.instant('MONTHS.MARCH'),
      this.translate.instant('MONTHS.APRIL'),
      this.translate.instant('MONTHS.MAY'),
      this.translate.instant('MONTHS.JUNE'),
      this.translate.instant('MONTHS.JULY'),
      this.translate.instant('MONTHS.AUGUST'),
      this.translate.instant('MONTHS.SEPTEMBER'),
      this.translate.instant('MONTHS.OCTOBER'),
      this.translate.instant('MONTHS.NOVEMBER'),
      this.translate.instant('MONTHS.DECEMBER')
    ];
  }

  loadInvestments(): void {
    this.loading = true;
    this.error = null;
    this.investmentsService.getAllInvestments().subscribe({
      next: (data) => {
        this.investmentItems = data;
        this.applyFilters();
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load investments data';
        this.loading = false;
        console.error('Error loading investments:', error);
      }
    });
  }

  generateAvailableYears(): void {
    const currentYear = new Date().getFullYear();
    this.availableYears = [];
    for (let year = currentYear - 5; year <= currentYear + 1; year++) {
      this.availableYears.push(year);
    }
  }

  applyFilters(): void {
    let filtered = [...this.investmentItems];

    // Apply search filter
    if (this.searchTerm.trim()) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(item =>
        item.type.toLowerCase().includes(term) ||
        item.description?.toLowerCase().includes(term) ||
        item.amount.toString().includes(term)
      );
    }

    // Apply date filters based on view mode
    if (this.viewMode === 'yearly') {
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        const itemYear = itemDate.getFullYear();
        return itemYear === this.selectedYear;
      });
    } else if (this.viewMode === 'monthly') {
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        const itemYear = itemDate.getFullYear();
        const itemMonth = itemDate.getMonth();
        return itemYear === this.selectedYear && itemMonth === this.selectedMonth;
      });
    } else if (this.viewMode === 'daily') {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      filtered = filtered.filter(item => {
        if (!item.date) return false;
        const itemDate = new Date(item.date);
        itemDate.setHours(0, 0, 0, 0);
        return itemDate.getTime() === today.getTime();
      });
    }
    // If viewMode is 'all', no date filtering is applied

    this.filteredItems = filtered;
    this.applyGrouping();
  }

  applyGrouping(): void {
    this.groupedData = TableGroupingService.groupBy(this.filteredItems, this.groupByField);
  }

  onGroupByChange(): void {
    this.applyGrouping();
  }

  toggleGroup(group: GroupedData<InvestmentItem>): void {
    group.expanded = !group.expanded;
  }

  expandAll(): void {
    this.groupedData.forEach(group => group.expanded = true);
  }

  collapseAll(): void {
    this.groupedData.forEach(group => group.expanded = false);
  }

  onSearch(): void {
    this.applyFilters();
  }

  onViewModeChange(): void {
    this.applyFilters();
  }

  onYearChange(): void {
    this.applyFilters();
  }

  onMonthChange(): void {
    this.applyFilters();
  }

  openAddForm(): void {
    this.editingItem = null;
    this.investmentForm.reset();
    const today = new Date();
    const day = String(today.getDate()).padStart(2, '0');
    const month = String(today.getMonth() + 1).padStart(2, '0');
    const year = today.getFullYear();
    this.investmentForm.patchValue({
      date: `${year}-${month}-${day}`
    });
    this.showForm = true;
  }

  editItem(item: InvestmentItem): void {
    this.editingItem = item;
    this.investmentForm.patchValue({
      date: item.date,
      type: item.type,
      amount: item.amount,
      description: item.description || ''
    });
    this.showForm = true;
  }

  cancelForm(): void {
    this.showForm = false;
    this.editingItem = null;
    this.investmentForm.reset();
  }

  onSubmit(): void {
    if (this.investmentForm.valid) {
      const formValue = this.investmentForm.value;

      if (this.editingItem) {
        // Update existing item
        this.investmentsService.updateInvestment(this.editingItem.id!, formValue).subscribe({
          next: () => {
            this.loadInvestments();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to update investment item';
            console.error('Error updating investment:', error);
          }
        });
      } else {
        // Create new item
        this.investmentsService.createInvestment(formValue).subscribe({
          next: () => {
            this.loadInvestments();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to create investment item';
            console.error('Error creating investment:', error);
          }
        });
      }
    } else {
      this.investmentForm.markAllAsTouched();
    }
  }

  deleteItem(item: InvestmentItem): void {
    if (confirm(`Are you sure you want to delete this ${item.type} investment?`)) {
      this.investmentsService.deleteInvestment(item.id!).subscribe({
        next: () => {
          this.loadInvestments();
        },
        error: (error) => {
          this.error = 'Failed to delete investment item';
          console.error('Error deleting investment:', error);
        }
      });
    }
  }

  getTotalInvestments(): number {
    return this.filteredItems.reduce((total, item) => total + item.amount, 0);
  }

  getFormFieldError(fieldName: string): string {
    const field = this.investmentForm.get(fieldName);
    if (field?.errors && field.touched) {
      if (field.errors['required']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} is required`;
      }
      if (field.errors['min']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} must be positive`;
      }
    }
    return '';
  }

  trackById(index: number, item: InvestmentItem): string {
    return item.id || index.toString();
  }

  getTypeClass(type: string): string {
    return 'type-' + type.toLowerCase().replace(/\s+/g, '-');
  }
}
<div class="investments-page">
  <div class="page-header">
    <div>
      <h1>{{ 'INVESTMENTS.TITLE' | translate }}</h1>
      <p>{{ 'INVESTMENTS.SUBTITLE' | translate }}</p>
    </div>
    <div class="header-actions">
      <a routerLink="/dashboard" class="btn btn-secondary">{{ 'NAV.DASHBOARD' | translate }}</a>
      <button (click)="openAddForm()" class="btn btn-primary">
        <span>➕</span>
        {{ 'INVESTMENTS.ADD_INVESTMENT' | translate }}
      </button>
    </div>
  </div>

  <!-- Error Message -->
  <div *ngIf="error" class="alert alert-error">
    <span>⚠️</span>
    {{ error }}
    <button (click)="error = null" class="alert-close">×</button>
  </div>

  <!-- Stats Card -->
  <div class="stats-card">
    <div class="stat-item">
      <div class="stat-label">{{ 'INVESTMENTS.TOTAL_INVESTMENTS' | translate }}</div>
      <div class="stat-value">${{ getTotalInvestments() | number:'1.0-0' }}</div>
    </div>
    <div class="stat-item">
      <div class="stat-label">{{ 'INVESTMENTS.FILTERED_ENTRIES' | translate }}</div>
      <div class="stat-value">{{ filteredItems.length }}</div>
    </div>
  </div>

  <!-- Search and Filters -->
  <div class="filters-section">
    <div class="search-box">
      <input
        type="text"
        [placeholder]="'INVESTMENTS.SEARCH_PLACEHOLDER' | translate"
        [(ngModel)]="searchTerm"
        (input)="onSearch()"
        class="form-input">
      <span class="search-icon">🔍</span>
    </div>

    <div class="date-filters">
      <div class="filter-group">
        <label>{{ 'FILTERS.VIEW_MODE' | translate }}:</label>
        <select [(ngModel)]="viewMode" (change)="onViewModeChange()" class="filter-select">
          <option value="all">{{ 'FILTERS.ALL_TIME' | translate }}</option>
          <option value="yearly">{{ 'FILTERS.YEARLY' | translate }}</option>
          <option value="monthly">{{ 'FILTERS.MONTHLY' | translate }}</option>
          <option value="daily">{{ 'FILTERS.DAILY' | translate }}</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'yearly' || viewMode === 'monthly'">
        <label>{{ 'FILTERS.YEAR' | translate }}:</label>
        <select [(ngModel)]="selectedYear" (ngModelChange)="onYearChange()" class="filter-select">
          <option *ngFor="let year of availableYears" [ngValue]="year">{{year}}</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'monthly'">
        <label>{{ 'FILTERS.MONTH' | translate }}:</label>
        <select [(ngModel)]="selectedMonth" (ngModelChange)="onMonthChange()" class="filter-select">
          <option *ngFor="let month of availableMonths; let i = index" [ngValue]="i">{{month}}</option>
        </select>
      </div>

      <div class="filter-group">
        <label>{{ 'FILTERS.GROUP_BY' | translate }}:</label>
        <select [(ngModel)]="groupByField" (ngModelChange)="onGroupByChange()" class="filter-select">
          <option value="none">{{ 'FILTERS.NO_GROUPING' | translate }}</option>
          <option value="type">{{ 'INVESTMENTS.TYPE' | translate }}</option>
          <option value="date">{{ 'COMMON.DATE' | translate }}</option>
        </select>
      </div>
    </div>
  </div>

  <!-- Investment Form Modal -->
  <div *ngIf="showForm" class="modal-overlay" (click)="cancelForm()">
    <div class="modal-content" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h2>{{ (editingItem ? 'COMMON.EDIT' : 'COMMON.ADD') | translate }} {{ 'INVESTMENTS.TITLE' | translate }}</h2>
        <button (click)="cancelForm()" class="modal-close">×</button>
      </div>

      <form [formGroup]="investmentForm" (ngSubmit)="onSubmit()" class="investment-form">
        <div class="form-row">
          <div class="form-group">
            <label class="form-label">{{ 'COMMON.DATE' | translate }} *</label>
            <input
              type="date"
              formControlName="date"
              class="form-input"
              [class.error]="getFormFieldError('date')">
            <div *ngIf="getFormFieldError('date')" class="field-error">
              {{ getFormFieldError('date') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">{{ 'INVESTMENTS.TYPE' | translate }} *</label>
            <select formControlName="type" class="form-select" [class.error]="getFormFieldError('type')">
              <option value="">{{ 'FORM.SELECT_TYPE' | translate }}</option>
              <option *ngFor="let type of investmentTypes" [value]="type.name_en">
                {{ getCategoryName(type) }}
              </option>
            </select>
            <div *ngIf="getFormFieldError('type')" class="field-error">
              {{ getFormFieldError('type') }}
            </div>
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label class="form-label">{{ 'COMMON.AMOUNT' | translate }} *</label>
            <div class="amount-input">
              <span class="currency-symbol">$</span>
              <input
                type="number"
                formControlName="amount"
                [placeholder]="'FORM.AMOUNT_PLACEHOLDER' | translate"
                step="0.01"
                min="0"
                class="form-input amount-field"
                [class.error]="getFormFieldError('amount')">
            </div>
            <div *ngIf="getFormFieldError('amount')" class="field-error">
              {{ getFormFieldError('amount') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">{{ 'COMMON.DESCRIPTION' | translate }}</label>
            <input
              type="text"
              formControlName="description"
              [placeholder]="'FORM.DESCRIPTION_PLACEHOLDER' | translate"
              class="form-input">
          </div>
        </div>

        <div class="form-actions">
          <button type="button" (click)="cancelForm()" class="btn btn-secondary">{{ 'COMMON.CANCEL' | translate }}</button>
          <button type="submit" [disabled]="!investmentForm.valid" class="btn btn-primary">
            {{ (editingItem ? 'COMMON.UPDATE' : 'COMMON.ADD') | translate }}
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Data Table -->
  <div class="table-container" *ngIf="!loading">
    <div class="group-controls" *ngIf="groupByField !== 'none' && groupedData.length > 1">
      <button (click)="expandAll()" class="btn btn-secondary btn-sm">{{ 'COMMON.EXPAND_ALL' | translate }}</button>
      <button (click)="collapseAll()" class="btn btn-secondary btn-sm">{{ 'COMMON.COLLAPSE_ALL' | translate }}</button>
    </div>
    <div *ngFor="let group of groupedData" class="group-section">
      <div class="group-header" *ngIf="groupByField !== 'none'" (click)="toggleGroup(group)">
        <div class="group-header-left">
          <span class="group-toggle">{{ group.expanded ? '▼' : '▶' }}</span>
          <h3>{{ group.groupValue }}</h3>
          <span class="group-count">({{ group.items.length }} {{ 'COMMON.ITEMS' | translate }})</span>
        </div>
        <span class="group-total">${{ group.total | number:'1.2-2' }}</span>
      </div>
      <table class="data-table" *ngIf="group.items.length > 0 && group.expanded">
        <thead>
          <tr>
            <th>{{ 'COMMON.DATE' | translate }}</th>
            <th>{{ 'INVESTMENTS.TYPE' | translate }}</th>
            <th>{{ 'COMMON.AMOUNT' | translate }}</th>
            <th>{{ 'COMMON.DESCRIPTION' | translate }}</th>
            <th>{{ 'COMMON.ACTIONS' | translate }}</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let item of group.items; trackBy: trackById" [class]="getTypeClass(item.type)">
            <td>{{item.date | customDate}}</td>
            <td>{{ 'INVESTMENTS.TYPES.' + item.type.replace(' ', '_').toUpperCase() | translate }}</td>
            <td class="amount-cell">${{item.amount | number:'1.2-2'}}</td>
            <td>{{item.description || '-'}}</td>
            <td class="actions-cell">
              <button class="btn btn-edit" (click)="editItem(item)">{{ 'COMMON.EDIT' | translate }}</button>
              <button class="btn btn-delete" (click)="deleteItem(item)">{{ 'COMMON.DELETE' | translate }}</button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>

    <div class="no-data" *ngIf="filteredItems.length === 0">
      <p>{{ 'INVESTMENTS.NO_ENTRIES' | translate }}</p>
    </div>
  </div>
</div>
